#include<bits/stdc++.h>
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
int n,a[100005];
void input(){
    n=read();
    for(int i=1;i<=n;i++)a[i]=read();
}
bool check(int x){
    int hp=x;
    for(int i=1;i<=n;i++) {
        hp+=a[i];
        if(hp<1)return false;
    }
    return true;
}
void work(){
    int l=1,r=1000*100000,mid;
    int ans=r;
    while(l<=r){
        mid=(l+r)/2;
        if(check(mid))ans=min(ans,mid),r=mid-1;
        else l=mid+1;
    }
    write(ans);
}
int main(void){
    input();
    work();
    return false;
}
